import { Component, h, Prop, Element, State, AttachInternals, Method, Watch, Listen, Event, EventEmitter } from '@stencil/core';
import { customTwMerge, findAssignedElementsByTag } from '../../utils/utils';
import { cardBaseBorderClasses, cardBaseClasses, cardDisabledClasses, cardElevationClasses, cardGhostBorderClasses, cardNoElevationClasses } from '../../utils/card-content-renderer';
import { getCardStateClasses, handleCardKeyDown, handleCardClick } from '../../utils/card.util';

export type MediaPosition = 'left' | 'right' | 'none';
export type CardVariant = 'actionable' | 'selectable' | 'non-actionable';

@Component({
  tag: 'wdpr-card-small',
  shadow: true,
  styles: `:host { display: block; width: 100%; }`,
  formAssociated: true,
})
export class WdprCardSmall {
  private _wdprCardSmallContent: HTMLWdprCardSmallContentElement[] | undefined;
  private _directActionButton: HTMLWdprButtonElement | undefined;
  private _directActionIconButton: HTMLWdprIconButtonElement | undefined;
  private _hasLabel: boolean = false;
  private _hasMedia: boolean = false;
  private _hasActionBadge: boolean = false;

  @Element() el: HTMLElement;

  @Prop({ reflect: true }) variant: CardVariant = 'actionable';
  @Prop() mediaPosition: 'leading' | 'trailing' | 'none' = 'leading';
  @Prop({ reflect: true }) ghost: boolean = false;
  @Prop({ reflect: true }) disabled: boolean = false;
  @Prop({ reflect: true }) fullWidth: boolean = false;
  @Prop({ reflect: true }) inverseColor: boolean = false;
  @Prop({ reflect: true }) name?: string;
  @Prop({ reflect: true }) backgroundSrc?: string | null = null;
  @Prop({ attribute: 'a11y-label' }) a11yLabel: string;

  @State() _selected: boolean = false;
  @State() _isMouseDown: boolean = false;
  @State() _hasAction: boolean;

  @Event() wdprCardClick!: EventEmitter<{ selected: boolean }>;
  @Event({ eventName: 'wdprDisabledChange' }) wdprDisabledChange!: EventEmitter<boolean>;

  @AttachInternals()
  internals: ElementInternals;

  componentDidLoad() {
    this._selectSlots();
    this._findCardContent();
    this._updateFormValue();
    this._initializeCardControls();
  }

  @Method()
  async refreshInternals() {
    this._updateFormValue();
  }

  @Watch('disabled')
  handleDisabledChange() {
    this._initializeCardControls();
    this._findCardContent();
    this.wdprDisabledChange?.emit(this.disabled);
    this._updateFormValue();
  }

  @Watch('_selected')
  onSelectedPropChange() {
    this._updateFormValue();
  }

  @Listen('formreset')
  handleFormReset() {
    this._selected = false;
    this._updateFormValue();
  }

  private _handleSelectedChange = () => {
    if (this.variant === 'non-actionable') return;

    this._selected = this.variant === 'selectable' ? !this._selected : false;

    this.wdprCardClick.emit({ selected: this._selected });
  };

  private _updateFormValue = () => {
    const shouldSubmit = !this.disabled;
    const formValue = shouldSubmit ? (this._selected ? 'selected' : 'not selected') : null;

    queueMicrotask(() => {
      if (this.internals && this.name != null) {
        this.internals?.setFormValue?.(formValue);
      }
    });
    this._updateValidity();
  };

  private _updateValidity = () => {
    if (this.disabled) {
      this.internals?.setValidity?.({});

      return;
    }

    const isValid = this._selected != null && typeof this._selected === 'boolean';

    if (isValid) {
      this.internals?.setValidity?.({});
    } else {
      this.internals?.setValidity?.({ valueMissing: true }, 'this field is required');
    }
  };

  private _selectSlots() {
    this._hasAction = !!this.el.querySelector('[slot="action"]');
    this._hasActionBadge = !!this.el.querySelector('[slot="action-badge"]');
    this._hasLabel = !!this.el.querySelector('[slot="status-label"]');
    this._hasMedia = !!this.el.querySelector('[slot="media"]');
  }

  private _findCardContent = () => {
    const slot = this.el.shadowRoot?.querySelector('slot[name="content"]');

    if (slot) {
      const assignedElement = findAssignedElementsByTag(slot as HTMLSlotElement, 'wdpr-card-small-content');
      this._wdprCardSmallContent = assignedElement as HTMLWdprCardSmallContentElement[] | undefined;

      if (this._wdprCardSmallContent) {
        this._wdprCardSmallContent.forEach(content => {
          content.disabled = this.disabled;
          content.inverseColor = this.inverseColor;
        });
      }
    }
  };

  private _initializeCardControls = () => {
    const slotAction = this.el.shadowRoot?.querySelector('slot[name="action"]');

    this._directActionButton = findAssignedElementsByTag(slotAction as HTMLSlotElement, 'wdpr-button')?.at(0) as HTMLWdprButtonElement;
    this._directActionIconButton = findAssignedElementsByTag(slotAction as HTMLSlotElement, 'wdpr-icon-button')?.at(0) as HTMLWdprIconButtonElement;

    const controls = [this._directActionButton, this._directActionIconButton].filter(Boolean);

    controls.forEach(control => {
      requestAnimationFrame(() => {
        control.disabled = this.disabled;
      });
    });
  };

  private _renderMediaSlot() {
    if (this.mediaPosition === 'none' || !this._hasMedia) {
      return null;
    }

    return (
      <div class="block items-center w-20 h-20 rounded-150 overflow-hidden">
        <slot name="media" />
      </div>
    );
  }

  private _renderActionSlot() {
    const actionPaddingClass = this.mediaPosition === 'trailing' && (this._directActionButton || this._directActionIconButton) ? 'pl-150' : '';

    return (
      <div class="flex items-center">
        {this._hasActionBadge && <div class='pr-050'>
          <slot name="action-badge" />
        </div>}

        <div class={actionPaddingClass}>
          <slot name="action" />
        </div>
      </div>
    );
  }

  private _toggleSelectionControl = () => {
    this._handleSelectedChange();

    if (this._directActionButton && !this._directActionButton.disabled) {
      this._directActionButton.click();
    } else if (this._directActionIconButton && !this._directActionIconButton.disabled) {
      this._directActionIconButton.click();
    }
  };

  private _handleKeyDown = (e: KeyboardEvent) => {
    handleCardKeyDown(e, this.el, this.disabled, this._toggleSelectionControl);
  };

  private _handleClick = (e: MouseEvent) => {
    handleCardClick(e, this.disabled, this._toggleSelectionControl);
  };

  get isSelectable() {
    return this.variant === 'selectable';
  }

  get cardRole() {
    return this.isSelectable && !this._hasAction ? 'button' : undefined;
  }

  get ariaPressed() {
    return this.isSelectable && this._selected ? true : undefined;
  }

  get ariaDisabled() {
    return this.isSelectable && this.disabled ? true : undefined;
  }

  get cardCardCursorClasses() {
    if (this.disabled || this.variant === 'non-actionable') return 'cursor-default';

    return 'cursor-pointer';
  }

  get cardClasses() {
    const cardWidthClasses = this.fullWidth ? '!w-full sm:!w-full !min-w-0 !max-w-none' : '';

    if (this.disabled) {
      const elevationClasses = (this.variant === 'non-actionable') ? 'elevation-none' : 'elevation-small-soft';

      return customTwMerge(cardDisabledClasses, cardWidthClasses, elevationClasses);
    }

    const cardStateClasses = !this.ghost && this.variant !== 'non-actionable' ? getCardStateClasses(this._selected, this._isMouseDown) : '';
    const cardBorderClasses = this.ghost ? cardGhostBorderClasses : this.variant !== 'non-actionable' ? cardBaseBorderClasses : '';
    const cardShadowBoxClasses = this.ghost || this.variant === 'non-actionable' ? cardNoElevationClasses : cardElevationClasses;
    const cardCursorClasses = this.cardCardCursorClasses;

    return customTwMerge(
      cardBaseClasses,
      cardBorderClasses,
      cardShadowBoxClasses,
      cardWidthClasses,
      cardCursorClasses,
      cardStateClasses
    );
  }

  render() {
    return (
      <div
        class={this.cardClasses}
        tabIndex={this.disabled ? -1 : 0}
        role={this.cardRole}
        onClick={this._handleClick}
        onKeyDown={this._handleKeyDown}
        onMouseDown={() => this._isMouseDown = true}
        onMouseUp={() => this._isMouseDown = false}
        aria-label={this.a11yLabel}
        aria-pressed={this.ariaPressed}
        aria-disabled={this.ariaDisabled}
      >
        {this._hasLabel && <slot name="status-label" />}

        {this.backgroundSrc ? (
          <div class="block absolute size-full top-0 left-0 z-0">
            <wdpr-media
              src={this.backgroundSrc}
              alt="Background image"
              aspect="square"
              objectFit="contain"
            ></wdpr-media>
          </div>) : (
          <div part="fill" class="flex absolute size-full top-0 left-0 z-0"></div>
        )}

        <div class="flex items-center w-full p-200 z-1">
          {this.mediaPosition === 'leading' && this._renderMediaSlot()}

          <div class={`flex-col flex flex-1 min-w-0 pr-150 ${this.mediaPosition === 'leading' && this._hasMedia ? 'pl-150' : ''}`}>
            <div class="flex items-start pb-100">
              <slot name="badge" />
            </div>
            <div class="flex-col flex">
              <slot name="content" />
            </div>
          </div>

          {this.mediaPosition === 'trailing' && this._renderMediaSlot()}

          {this._renderActionSlot()}
        </div>
      </div >
    );
  }
}
